import React, { useState, useRef, useEffect } from "react";
import axios from "axios";

function App() {

  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);

  const bottomRef = useRef(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const sendMessage = async () => {

    if (!input.trim()) return;

    const userMessage = {
      role: "user",
      text: input,
      time: new Date().toLocaleTimeString()
    };

    setMessages(prev => [...prev, userMessage]);
    setInput("");
    setLoading(true);

    try {

      const res = await axios.post(
        "http://localhost:5001/chat",
        { message: input }
      );

      const aiMessage = {
        role: "ai",
        text: res.data.reply,
        time: new Date().toLocaleTimeString()
      };

      setMessages(prev => [...prev, aiMessage]);

    } catch (err) {

      setMessages(prev => [
        ...prev,
        { role: "ai", text: "Error contacting AI", time: "" }
      ]);

    }

    setLoading(false);
  };

  const handleKeyPress = (e) => {
    if (e.key === "Enter") {
      sendMessage();
    }
  };

  const clearChat = () => {
    setMessages([]);
  };

  return (

    <div style={styles.container}>

      <div style={styles.chatBox}>

        <div style={styles.header}>
          AI Assistant
          <button style={styles.clear} onClick={clearChat}>
            Clear
          </button>
        </div>

        <div style={styles.messages}>

          {messages.map((msg, index) => (

            <div
              key={index}
              style={
                msg.role === "user"
                  ? styles.userRow
                  : styles.aiRow
              }
            >

              <div style={styles.avatar}>
                {msg.role === "user" ? "🧑" : "🤖"}
              </div>

              <div style={styles.messageBubble}>

                <div>{msg.text}</div>

                <div style={styles.time}>
                  {msg.time}
                </div>

              </div>

            </div>

          ))}

          {loading && (
            <div style={styles.aiRow}>
              <div style={styles.avatar}>🤖</div>
              <div style={styles.messageBubble}>
                AI is thinking...
              </div>
            </div>
          )}

          <div ref={bottomRef} />

        </div>

        <div style={styles.inputArea}>

          <input
            style={styles.input}
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyPress}
            placeholder="Ask something..."
          />

          <button
            style={styles.send}
            onClick={sendMessage}
          >
            Send
          </button>

        </div>

      </div>

    </div>

  );
}

const styles = {

  container: {
    height: "100vh",
    background: "#0f172a",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    fontFamily: "Arial"
  },

  chatBox: {
    width: "600px",
    height: "650px",
    background: "#1e293b",
    borderRadius: "12px",
    display: "flex",
    flexDirection: "column",
    overflow: "hidden"
  },

  header: {
    padding: "15px",
    color: "white",
    fontSize: "18px",
    borderBottom: "1px solid #334155",
    display: "flex",
    justifyContent: "space-between"
  },

  clear: {
    background: "#ef4444",
    border: "none",
    color: "white",
    padding: "5px 10px",
    borderRadius: "6px",
    cursor: "pointer"
  },

  messages: {
    flex: 1,
    overflowY: "auto",
    padding: "20px",
    display: "flex",
    flexDirection: "column",
    gap: "15px"
  },

  userRow: {
    display: "flex",
    justifyContent: "flex-end",
    gap: "10px"
  },

  aiRow: {
    display: "flex",
    justifyContent: "flex-start",
    gap: "10px"
  },

  avatar: {
    fontSize: "22px"
  },

  messageBubble: {
    background: "#334155",
    color: "white",
    padding: "10px 15px",
    borderRadius: "10px",
    maxWidth: "70%"
  },

  time: {
    fontSize: "10px",
    opacity: 0.6,
    marginTop: "5px"
  },

  inputArea: {
    display: "flex",
    padding: "15px",
    borderTop: "1px solid #334155"
  },

  input: {
    flex: 1,
    padding: "10px",
    borderRadius: "8px",
    border: "none",
    outline: "none"
  },

  send: {
    marginLeft: "10px",
    padding: "10px 15px",
    border: "none",
    borderRadius: "8px",
    background: "#3b82f6",
    color: "white",
    cursor: "pointer"
  }

};

export default App;
